import { useCallback } from 'react';

import { useCanvas } from '../../../../canvas/hooks/useCanvas.js';

export const CanvasContextRestore = () => {
  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.restore();

    return false;
  }, []);

  useCanvas('canvas-context-restore', draw);

  return null;
};
